的原因、範例及如何管理。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:33+00:00", "source_pdf_sha1": "6e1c803471d2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "212", "s": "0607", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育心理學", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "教育行政"}'::jsonb, NULL),
